<template>
    <el-container style="height: 100vh;">
        <!-- 头部 -->
        <el-header style="background-color: #409EFF; color: #fff; padding: 0;">
            <el-row :gutter="10" type="flex" justify="space-between" align="center" style="height: 100%;">
                <!-- 头部左边的按钮 -->
                <!-- 空白列，用于调整按钮位置 -->
                <el-col :span="1"></el-col>
                <el-col :span="1" style="text-align: center;">
                    <el-button type="text" icon="el-icon-menu" @click="showDrawer = true" style="color: #fff;"></el-button>
                </el-col>
                <!-- 头部标题 -->
                <el-col :span="20" style="text-align: center;">
                    <p style="font-size: 20px; font-family: 'Microsoft YaHei', sans-serif;">Lysssyo's Personal Page</p>
                </el-col>
                <el-col :span="2"></el-col>
            </el-row>
        </el-header>


        <!-- 信息展示部分 -->
        <el-main style="overflow-y: auto; padding: 20px;">
            <!-- 在此处放置您的信息展示内容 -->
            <div style="height: 1500px;">
                <!-- 使用 mavon-editor 组件展示 Markdown 内容 -->
                <mavon-editor style="position:static" :value="markdownContent" :editable="false" :subfield="false"
                    :defaultOpen="'preview'" :toolbarsFlag="false" :scrollStyle="true" :ishljs="true" />
            </div>
        </el-main>

        <!-- 滑出菜单 -->
        <!-- 滑出菜单 -->
        <el-drawer :visible.sync="showDrawer" :direction="direction" :before-close="handleClose" :show-close="false"
            size="45%" style="z-index: 999 ">
            <!-- 菜单内容 -->
            <el-menu default-active="1-1" :unique-opened="true" style="background-color:#ffffff text-color:#333
          active-text-color:#333">
                <el-submenu index="1">
                    <template slot="title">
                        <i class="el-icon-collection"></i>
                        <span>Learning notes</span>
                    </template>
                    <el-menu-item index="1-1">DataStructure</el-menu-item>
                    <el-menu-item index="1-2">Item 2</el-menu-item>
                </el-submenu>
                <el-submenu index="2">
                    <template slot="title">
                        <i class="el-icon-menu"></i>
                        <span>Submenu 2</span>
                    </template>
                    <el-menu-item index="2-1">Item 1</el-menu-item>
                    <el-menu-item index="2-2">Item 2</el-menu-item>
                </el-submenu>
            </el-menu>
        </el-drawer>
    </el-container>
</template>
  
<script>
import axios from 'axios';
import 'mavon-editor/dist/css/index.css';
import { mavonEditor } from 'mavon-editor';
export default {
    components: {
        mavonEditor
    },
    data() {
        return {
            markdownContent: '',
            showDrawer: false,
            direction: 'ltr' // 从左往右滑出
        };
    },
    created() {
        this.fetchMarkdownContent();
    },
    methods: {
        handleClose() {
            this.showDrawer = false;
        },
        fetchMarkdownContent() {
            const githubUrl = 'https://raw.githubusercontent.com/Lysssyo/MyAlgorithm/main/DataStructuresAlgorithm.md';
            axios.get(githubUrl)
                .then(response => {
                    let markdownContent = response.data;
                    // 替换图片标签为展示图片的 HTML 标签
                    markdownContent = markdownContent.replace(
                        /<\s*img\s+src="([^"]*)"\s+alt="([^"]*)"\s+style="([^"]*)"\s*\/>|!\[.*?\]\((.*?)\)/g,
                        (match, imgSrc, imgAlt, imgStyle, markdownImageUrl) => {
                            // 提取正确的图片链接
                            const imageUrl = imgSrc || markdownImageUrl;
                            // 构建 GitHub 仓库中图片的 URL
                            const githubImageUrl = `https://raw.githubusercontent.com/Lysssyo/MyAlgorithm/main/${imageUrl}`;
                            // 返回展示图片的 HTML 标签
                            return `<img src="${githubImageUrl}" alt="${imgAlt}" style="${imgStyle}" />`;
                        }
                    );
                    this.markdownContent = markdownContent;
                })
                .catch(error => {
                    console.error('Error fetching markdown content:', error);
                });
        }
    }
};
</script>
  
<style>
/* 自定义菜单样式 */
.el-menu {
    width: 400px;
    /* 设置菜单宽度 */
    padding-left: 0;
    /* 移除菜单的左边内边距 */
}

.el-submenu__title {
    height: 50px;
    /* 设置菜单项的高度 */
    line-height: 50px;
    /* 设置菜单项文字的垂直居中 */
    padding-left: 0 !important;
    /* 移除菜单项的左边内边距 */
    margin-left: 0 !important;
    /* 移除菜单项的左边外边距 */
}
</style>